/** Look up a single tool by its ID (Result Code). */
export function getToolById(id: string): WikiToolDetail | undefined {
  return tools.find(t => t.id === id);
}

/** Return all tools. */
export function getAllTools(): WikiToolDetail[] {
  return tools;
}

/** Return unique values for a given facet field across all tools. */
export function getUniqueFacetValues(field: keyof WikiToolDetail): string[] {
  const values = new Set<string>();
  for (const tool of tools) {
    const val = tool[field];
    if (Array.isArray(val)) {
      val.forEach(v => values.add(String(v)));
    } else if (val != null) {
      values.add(String(val));
    }
  }
  return Array.from(values).sort();
}
